module RefModule(
    input clk,
    input reset,    
    input j,
    input k,
    output out);parameter OFF=0, ON=1; 
    reg unused_state, next_state;

    always @(*) begin

        case(unused_state)
            OFF: next_state = (j)? ON:OFF;
            ON: next_state = (k)? OFF:ON;
        endcase
    end

    always @(posedge clk) begin

        if (reset)
            unused_state <= OFF;
        else
            unused_state <= next_state;
    end


    assign out = (unused_state == ON);

endmodule
